    int count = 0;

    for (int i = 0; i < 2; i++) {
        ssize_t n = read(sfd, &info, sizeof(info));
        if (n != sizeof(info)) { perror("read"); break; }
        printf("Read signal: %d", info.ssi_signo);
        if (info.ssi_signo == SIGUSR1) printf(" (SIGUSR1)");
        if (info.ssi_signo == SIGUSR2) printf(" (SIGUSR2)");
